const raw = $input.first().json;
const text = String(raw.query ?? raw.chatInput ?? raw.issue_number ?? raw.input ?? '').trim();
const m = text.match(/#?(\d{3,6})/);
if (!m) {
  return [{ json: { issueNumber: null, response: 'Provide an issue number (e.g. 14361 or #14361).' } }];
}
return [{ json: { issueNumber: parseInt(m[1], 10) } }];

const parsed = $('Parse input').first().json;
if (!parsed.issueNumber) {
  return [{ json: { response: parsed.response } }];
}
const issueNumber = parsed.issueNumber;
const issue = await this.helpers.httpRequestWithAuthentication.call(this, 'githubApi', {
  method: 'GET',
  url: `https://api.github.com/repos/n8n-io/n8n/issues/${issueNumber}`,
  json: true,
});
const commentsRaw = await this.helpers.httpRequestWithAuthentication.call(this, 'githubApi', {
  method: 'GET',
  url: `https://api.github.com/repos/n8n-io/n8n/issues/${issueNumber}/comments?per_page=100`,
  json: true,
});
return [{ json: { issueNumber, issue, comments: Array.isArray(commentsRaw) ? commentsRaw : [] } }];

const data = $('Fetch thread').first().json;
if (data.response) {
  return [{ json: { response: data.response } }];
}
const { issueNumber, issue, comments: commentsRaw } = data;
const skip = new Set(['dependabot[bot]', 'n8n-io[bot]', 'github-actions[bot]']);
const comments = commentsRaw.filter((c) => c.body && !skip.has(c.user?.login)).slice(0, 30);
const thread = comments.map((c) =>
  `@${c.user?.login} (${c.author_association}): ${(c.body || '').replace(/\s+/g, ' ').slice(0, 500)}`
).join('\n');
const labels = (issue.labels || []).map((l) => l.name).join(', ');
const mcpHint = /\bmcp\b/i.test((issue.title || '') + (issue.body || ''))
  ? 'Verified MCP entry points: packages/@n8n/nodes-langchain/nodes/mcp/McpTrigger/McpTrigger.node.ts and McpServer.ts. Compare Webhook.node.ts for request metadata exposure.'
  : '';
const synthPrompt = `You are a senior n8n maintainer. Summarize this GitHub issue thread for a contributor.

Issue #${issueNumber}: ${issue.title}
Labels: ${labels}
Body: ${(issue.body || '').slice(0, 800)}

Comments (${comments.length}):
${thread}

Write Markdown with EXACTLY:
## Thread summary
## Maintainer signals

Be factual. Under 200 words.`;
const synth = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://10.0.0.4:11434/api/generate',
  body: { model: 'llama3.2:3b', prompt: synthPrompt, stream: false, options: { temperature: 0.2, num_ctx: 8192 } },
  json: true,
});
const proposePrompt = `Based on this issue synthesis, propose a contributor approach for n8n (Node.js/TypeScript workflow automation).

${synth.response}
${mcpHint ? '\nKnown code entry points:\n' + mcpHint : ''}

Write Markdown with EXACTLY:
## Proposed approach
## Scope (S/M/L)
## Good first issue (yes/no)
## Risks

Hypotheses only — admit uncertainty. Under 200 words.`;
const prop = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://10.0.0.4:11434/api/generate',
  body: { model: 'llama3.2:3b', prompt: proposePrompt, stream: false, options: { temperature: 0.2, num_ctx: 8192 } },
  json: true,
});
const url = issue.html_url || `https://github.com/n8n-io/n8n/issues/${issueNumber}`;
return [{
  json: {
    response: `# Deep dive #${issueNumber}\n\n${url}\n\n${synth.response}\n\n---\n\n${prop.response}`,
  },
}];
